const float L1_B3[16] = {-0.355084f, 0.279569f, -0.279790f, 0.309875f, 0.325792f, -0.082132f, -0.266639f, -0.062435f, 0.101880f, 0.262019f, -0.245410f, 0.033057f, -0.011713f, -0.113660f, 0.272643f, 0.045962f};

const float L1_W_OUT[16] = {-0.115670f, -0.428789f, 0.002584f, -0.363037f, -0.175552f, 0.752490f, -0.471238f, 0.255489f, -0.694313f, -0.703113f, -0.265421f, -0.742092f, 0.155937f, 0.342308f, 0.142257f, 0.287493f};
const float L1_B_OUT = 0.020447f;

int model1_1(const float fv[20]) {
    float x[20];
    for (int i = 0; i < 20; i++)
        x[i] = (fv[i] - L1_SCALER_MEAN[i]) / L1_SCALER_SCALE[i];

    // Hidden layer 0 (20 -> 128) ReLU
    float h0[128];
    for (int j = 0; j < 128; j++) {
        float sum = L1_B0[j];
        for (int i = 0; i < 20; i++)
            sum += x[i] * L1_W0[i][j];
        h0[j] = sum > 0.0f ? sum : 0.0f;
    }

    // Hidden layer 1 (128 -> 64) ReLU
    float h1[64];
    for (int j = 0; j < 64; j++) {
        float sum = L1_B1[j];
        for (int i = 0; i < 128; i++)
            sum += h0[i] * L1_W1[i][j];
        h1[j] = sum > 0.0f ? sum : 0.0f;
    }

    // Hidden layer 2 (64 -> 32) ReLU
    float h2[32];
    for (int j = 0; j < 32; j++) {
        float sum = L1_B2[j];
        for (int i = 0; i < 64; i++)
            sum += h1[i] * L1_W2[i][j];
        h2[j] = sum > 0.0f ? sum : 0.0f;
    }

    // Hidden layer 3 (32 -> 16) ReLU
    float h3[16];
    for (int j = 0; j < 16; j++) {
        float sum = L1_B3[j];
        for (int i = 0; i < 32; i++)
            sum += h2[i] * L1_W3[i][j];
        h3[j] = sum > 0.0f ? sum : 0.0f;
    }

    // Output layer (16 -> 1) - binary classification
    float score = L1_B_OUT;
    for (int j = 0; j < 16; j++)
        score += h3[j] * L1_W_OUT[j];

    // sigmoid threshold at 0.5 - equivalent to score > 0
    return score > 0.0f ? 1 : 0;  // 0=non-target, 1=target
}
